"""
MKT Original Commentary — Genesis chapters 41–42
Run: python3 scripts/zc-original-genesis-41-42.py

Source data used:
- data/interlinear/genesis.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/genesis.json (MKT text)

Key decisions:
- Egyptian loanwords (ḥarṭummîm, ʾaḥû, yĕʾôr, ʾaḇrēḵ, ṣāpĕnat-paʿnēaḥ,
  ʾāsĕnat) are identified as loanwords; their Egyptian etymology is given
  where known but the commentary is honest about areas of scholarly dispute
- ruaḥ ʾElohim (v.38) on Pharaoh's lips: treated as Pharaoh using his own
  religious vocabulary (divine spirit) while the Hebrew narrator presents it
  as the Spirit of Israel's God — the two meanings are noted
- ʾaḇrēḵ (v.43): acknowledged as a genuine hapax with uncertain etymology;
  "bow the knee" reading is noted alongside others
- Manasseh/Ephraim name etymologies (vv.51-52): the Hebrew wordplays are
  the primary content; the later tribal history is not anticipated here
- Ch 42: the brothers' speech in v.21 (seeing Joseph's distress in the pit)
  is the first explicit retrospective confirmation of what ch. 37 did not
  spell out — noted as narratively significant disclosure of interior detail
- Joseph's weeping (42:24) is the first of five such episodes; the pattern
  of private weeping before controlled public speech is noted
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "41": {
    "1": '<p><strong>מִקֵּץ שְׁנָתַיִם יָמִים</strong> (<em>miqqēṣ šĕnātayim yāmîm</em>) — "at the end of two full years." <em>Miqqēṣ</em> (at the end of — from <em>qēṣ</em>, end, limit; cf. 8:6 where the same phrase marks the end of Noah\'s waiting period). <em>Šĕnātayim</em> (dual: two years) + <em>yāmîm</em> (days — a supplementary indicator of full years; "two years of days" = two complete years; the idiom emphasizes that the entire period elapsed). Two full years after the cupbearer\'s restoration and Joseph\'s forgotten petition — the divine timetable operates on its own schedule. <strong>עֹמֵד עַל-הַיְאֹר</strong> (standing by the Nile) — <em>yĕʾôr</em> (the Nile — an Egyptian loanword, from Egyptian <em>j\'rw</em>, "river/canal"; the standard Hebrew word for the Nile throughout the Exodus narrative; its presence here is one of several authentically Egyptian elements in the Joseph narrative).</p>',
    "2": '<p><strong>שֶׁבַע פָּרוֹת בְּרִיאוֹת וּטֹבוֹת מַרְאֶה</strong> (<em>šeḇaʿ pārôt bĕrîʾôt ûṭōḇôt marʾeh</em>) — "seven cows, fat and good of appearance." <em>Pārāh</em> (cow — female bovine specifically; appears 26× in this chapter, uniquely concentrated; in Egyptian religion, the cow was sacred to Hathor, goddess of fertility and beauty; the dream operates within the Egyptian religious register without acknowledging it). <em>Bārîʾ</em> (fat, healthy, well-fed — from a root meaning to be fat/strong; the same adjective used in Dan 1:15 for the healthier-looking Daniel and his companions). <strong>בָּאַחוּ</strong> (<em>bāʾaḥû</em>, among the reeds) — <em>ʾāḥû</em> (marsh grass, reeds — an Egyptian loanword from Egyptian <em>ꜣḫw</em>, "marsh plants"; a rare word in Hebrew appearing only here and in Gen 41:18 and Job 8:11; its Egyptian origin anchors the dream in the Nile-delta landscape).</p>',
    "3": '<p><strong>רָעוֹת מַרְאֶה וְדַקּוֹת בָּשָׂר</strong> (<em>rāʿôt marʾeh wĕdaqqôt bāśār</em>) — "ugly of appearance and lean of flesh." <em>Rāʿ marʾeh</em> (ugly/bad of appearance) — the opposite of the good-appearance formula; <em>daq bāśār</em> (thin of flesh) — the emaciated cattle of famine; <em>bāśār</em> (flesh, body) used for the physical condition of the animal. The seven lean cows standing beside the seven fat ones on the riverbank create the dream\'s symbolic tableau: the abundance and the famine exist simultaneously in the vision before the historical sequence unfolds.</p>',
    "4": '<p><strong>וַתֹּאכַלְנָה הַפָּרוֹת רָעוֹת הַמַּרְאֶה</strong> — "the ugly-looking cows ate the seven fat, good cows." The narrative reversal embedded in the dream: the weaker consume the stronger. <em>Wayyîqaṣ parʿōh</em> (Pharaoh woke up) — the first awakening between the two dreams; the structure of double-dream-with-awakening is a recognized dream-type in ANE literature; the doubling confirms and intensifies the message (cf. v. 32). Pharaoh\'s waking — seeing it was a dream — increases his disturbance (v. 8) rather than relieving it.</p>',
    "5": '<p><strong>שֶׁבַע שִׁבֳּלִים עֹלוֹת בְּקָנֶה אֶחָד</strong> (<em>šeḇaʿ šibbŏlîm ʿōlôt bĕqāneh ʾeḥāḏ</em>) — "seven heads of grain growing on a single stalk." <em>Šibbōlet</em> (head of grain, ear of grain — the same word that becomes the famous pronunciation test in Judg 12:6 ["say šibbōlet"]; here its agricultural meaning governs). <em>Bĕrîʾôt wĕṭōḇôt</em> (healthy and good) — the same pair of adjectives as the fat cows (v. 2); the parallel vocabulary between the two dreams signals their identical meaning. A single stalk producing seven heads is itself a symbol of extraordinary abundance.</p>',
    "6": '<p><strong>שֶׁבַע שִׁבֳּלִים דַּקּוֹת וּשְׁדוּפֹת קָדִים</strong> (<em>šeḇaʿ šibbŏlîm daqqôt ûšĕḏûpōt qāḏîm</em>) — "seven thin heads scorched by the east wind." <em>Šĕḏûpāh</em> (scorched, blasted — Qal passive participle of <em>šāḏap</em>, to scorch, blight; the word for crop-disease/blight appears in Deut 28:22 as a covenant curse; 1 Kgs 8:37; Amos 4:9; Hag 2:17 — grain-blight is always in the context of divine judgment). <em>Qāḏîm</em> (east wind — the hot, dry sirocco from the east/southeast; cf. Ezek 17:10; 19:12; Hos 13:15; Jon 4:8; the east wind withers, scatters, and destroys in OT poetry and prophecy).</p>',
    "7": '<p><strong>וַתִּבְלַעְנָה הַשִּׁבֳּלִים הַדַּקּוֹת</strong> — "the thin heads swallowed the seven fat heads." The same swallowing-verb (<em>bālaʿ</em>) as the lean cows in v. 4 (<em>tōʾkalnāh</em>); the second dream uses a different verb but the same action-structure. <em>Wayyîqaṣ parʿōh wĕhinnēh ḥălôm</em> (Pharaoh woke up — and behold it was a dream) — the <em>wĕhinnēh</em> (and behold) of abrupt realization; the twice-awakened Pharaoh now knows he has had two vivid dreams; his morning disturbance (v. 8) shows they did not feel like ordinary dreams.</p>',
    "8": '<p><strong>וַיְהִי בַבֹּקֶר וַתִּפָּעֶם רוּחוֹ</strong> (<em>wayhî ḇabbōqer wattippāʿem rûḥô</em>) — "in the morning his spirit was troubled." <em>Pāʿam</em> (Niphal: to be disturbed, agitated — used for the agitation of the spirit before divine revelation; cf. Dan 2:1, 3 where Nebuchadnezzar\'s spirit is <em>nippāʿam</em> after his dream; the Niphal expresses an involuntary disturbance of the interior). <strong>חַרְטֻמֵּי מִצְרָיִם</strong> (<em>ḥarṭummê miṣrāyim</em>, the magicians of Egypt) — <em>ḥarṭummîm</em> (an Egyptian loanword from Egyptian <em>ḥr-tp</em>, "chief lector priest" or "keeper of the sacred books"; the professional dream-interpreters and ritual specialists of the Egyptian court; the same word appears in Exod 7:11, 22; 8:3, 14-15; 9:11 where the same class fails against Moses\' signs). Their failure here is theologically significant: the interpretive tradition of Egypt cannot read what God has revealed; <strong>וְחַכְמֵי מִצְרָיִם</strong> (the wise men of Egypt) — the <em>ḥăḵāmîm</em> (wisdom-professionals) whose failure underscores that <em>ḥōkmāh</em> (wisdom) in Egypt is insufficient to decode God\'s revelation.</p>',
    "9": '<p><strong>אֶת-חֲטָאַי אֲנִי מַזְכִּיר הַיּוֹם</strong> (<em>ʾet-ḥăṭāʾay ʾănî mazkîr hayyôm</em>) — "my shortcomings I am making known today." The cupbearer uses <em>ḥēṭ</em> (sin, offense, shortcoming — the standard word for sin: moral wrong, offense against a superior, falling short of a standard); here likely referring to a failure of his official duty or his neglect of Joseph. <em>Mazkîr</em> (Hiphil participle of <em>zākar</em>, to remember; Hiphil = to cause to remember, to mention, to record) — "I am causing to be remembered" = I am now bringing to mind what I should have mentioned before; the verb of memory is used for both the cupbearer\'s self-disclosure and for Joseph\'s earlier "remembering" of the dreams (42:9).</p>',
    "10": '<p>The cupbearer recaps the events of ch. 40: Pharaoh\'s anger (<em>qāṣap</em>, to be angry — the same verb used for Pharaoh\'s anger in 40:2), the imprisonment in the captain of the guard\'s house (<em>bêt śar haṭṭabbāḥîm</em> — the same house where Joseph was confined). The recap serves to introduce Joseph to Pharaoh\'s attention as a reliable dream-interpreter with a proven track record.</p>',
    "11": '<p><strong>וַנַּחַלְמָה חֲלוֹם בְּלַיְלָה אֶחָד אֲנִי וָהוּא</strong> — "we each dreamed a dream in one night, he and I." The single-night double-dream confirms the simultaneous divine communication to both prisoners. <em>Kĕpitron ḥălōmô</em> (according to the interpretation of his dream) — <em>pitrôn</em> (interpretation — an Egyptian loanword from Egyptian <em>ptr</em>, "to understand/interpret"; appears only in the Joseph narrative: 40:5, 8, 12, 16, 18; 41:11); the concentration of this loanword in the Joseph narrative is part of its Egyptian vocabulary cluster.</p>',
    "12": '<p><strong>נַעַר עִבְרִי</strong> (<em>naʿar ʿiḇrî</em>, a young Hebrew man) — "a young Hebrew there with us." <em>Naʿar</em> (young man — the same word applied to Joseph in 37:2; the cupbearer remembers Joseph as a subordinate; the word carries the social implication of servant/junior). <em>ʿIḇrî</em> (Hebrew — the ethnic designation; from <em>ʿēḇer</em>, one who crosses over; the term is used to designate Israelites to non-Israelites throughout the Exodus narrative: 1:15, 16, 19; 2:7, 11, 13; 3:18 etc.; the cupbearer identifies Joseph by his ethnicity, not his name or status). <em>ʿEḇeḏ śar haṭṭabbāḥîm</em> (servant of the captain of the guard) — the social position the cupbearer remembers Joseph as holding; Joseph was Potiphar\'s servant, then the captain\'s prisoner — the cupbearer\'s memory focuses on the prison context.</p>',
    "13": '<p><strong>כַּאֲשֶׁר פָּתַר-לָנוּ כֵּן הָיָה</strong> (<em>kaʾăšer pātar-lānû kēn hāyāh</em>) — "just as he interpreted to us, so it was." <em>Pātar</em> (to interpret a dream — a verb of uncertain etymology, possibly also Egyptian in background; used exclusively with dream-interpretation in Genesis: 40:8, 12, 16, 18, 22; 41:8, 12, 13, 15); the fulfilled interpretation is the certification of Joseph\'s interpretive gift: it was not guesswork but genuine revelation. <em>Wayyitlēhû</em> (and he was impaled) — <em>tālāh</em> (to hang, impale — the form of execution; whether this was hanging on a gallows or impalement on a post is debated; the verb covers both; the baker\'s fate is confirmed as the dream predicted).</p>',
    "14": '<p><strong>וַיְרִיצֻהוּ מִן-הַבּוֹר</strong> (<em>wayyĕrîṣûhû min-habbôr</em>) — "they rushed him from the pit/dungeon." <em>Rîṣ</em> (Hiphil: to cause to run, to bring quickly — the urgency of the royal summons); <em>bôr</em> (pit, cistern, dungeon — the same word as the dry cistern of 37:24 into which the brothers threw Joseph; Joseph\'s prison in Egypt is also called a <em>bôr</em>; the word brackets Joseph\'s entire period of humiliation: from the pit in Canaan to the pit-dungeon in Egypt, and now the release from both). <strong>וַיְגַלַּח וַיְחַלֵּף שִׂמְלֹתָיו</strong> (he shaved and changed his clothes) — <em>gāllaḥ</em> (to shave — Egyptians, unlike Hebrews, shaved their entire bodies including facial hair; Herodotus 2.36 notes that Egyptian priests shave; Joseph\'s shaving is cultural adaptation for the royal court appearance; Pharaoh\'s court required a clean-shaven face).</p>',
    "15": '<p>Pharaoh\'s statement — "I have heard it said of you that when you hear a dream you can interpret it" — the reputation precedes Joseph; the cupbearer\'s report has established him as a dream-interpreter. The verb <em>šāmaʿ</em> (to hear, to hear about) — Pharaoh has "heard" about Joseph\'s gift; the same hearing-verb that drives the patriarchal narrative of providence.</p>',
    "16": '<p><strong>בִּלְעָדָי אֱלֹהִים יַעֲנֶה אֶת-שְׁלוֹם פַּרְעֹה</strong> (<em>bilʿāḏāy ʾĔlōhîm yaʿăneh ʾet-šĕlôm parʿōh</em>) — "apart from me — God will answer Pharaoh\'s welfare." <em>Bilʿāḏāy</em> (apart from me, without me — the disclaimer formula; Joseph explicitly removes himself from the interpretive credit before he has even heard the dream). <em>Yaʿăneh</em> (Qal imperfect of <em>ʿānāh</em>, to answer, respond — future action) — the answer will come; its source is God, not Joseph. <em>Šĕlôm parʿōh</em> (Pharaoh\'s šālôm) — not a greeting but "what will bring Pharaoh to peace/resolution"; the <em>šālôm</em>-word applied to the resolution of Pharaoh\'s disturbed spirit (v. 8). Joseph\'s humility before Pharaoh echoes and inverts the brothers\' self-humiliation before Joseph — one is genuine, the other forced.</p>',
    "17": '<p>Pharaoh retells his dreams in vv. 17-24 — a near-verbatim repetition of vv. 1-7, with minor variations that the narrator includes: Pharaoh says "I had never seen such ugly cows in all the land of Egypt" (v. 19 — an intensification not in the original account); "they looked just as ugly as before" (v. 21 — a detail added in the retelling). The variations in Pharaoh\'s retelling versus the narrator\'s original account is a common feature of biblical narrative (cf. Abraham\'s servant retelling the commission story in ch. 24 with variations); the repetition with minor variations is not an error but reflects the narrator\'s technique of characterization through speech.</p>',
    "18": '<p>The fat cows in Pharaoh\'s retelling: <em>bĕrîʾôt ûṭōḇôt marʾeh</em> (fat and good of appearance) — the same adjectives as v. 2 but in reverse order (v. 2: sleek and fat; v. 18: fat and sleek); the minor reordering is characteristic of retelling. The detail of the Nile-bank setting is preserved: the connection between the Nile, Egypt\'s fertility, and Pharaoh\'s dream is maintained throughout the retelling.</p>',
    "19": '<p><strong>וְהִנֵּה שֶׁבַע-פָּרוֹת אֲחֵרוֹת עֹלוֹת אַחֲרֵיהֶן דַּלּוֹת וְרָעוֹת תֹּאַר מְאֹד</strong> — Pharaoh adds the intensifier <em>mĕʾōḏ</em> (very much) in his retelling: "very ugly" — the emotional impact of the disturbing cows is expressed more emphatically in his direct report. <strong>לֹא-רָאִיתִי כָהֵנָּה בְּכָל-אֶרֶץ מִצְרָיִם לָרֹעַ</strong> (I had never seen such ugly cows in all the land of Egypt) — the superlative "never seen such" is Pharaoh\'s subjective memory-addition to the dream account; Egypt is famous for its productive cattle; cows this poor were an aberration from the Egyptian agricultural norm.</p>',
    "20": '<p>The eating of the fat cows by the lean: Pharaoh\'s retelling compresses the narrative slightly; the detail that "no one could tell they had eaten them" appears in v. 21 as an addition unique to Pharaoh\'s version. The famine that is coming will be so severe that the years of abundance will be completely forgotten — the retrospective look will show no evidence of prior prosperity.</p>',
    "21": '<p><strong>וְלֹא נוֹדַע כִּי-בָאוּ אֶל-קִרְבֶּנָה</strong> (<em>wĕlōʾ nôḏaʿ kî-ḇāʾû ʾel-qirḇennāh</em>) — "no one could tell that they had entered their belly." <em>Nôḏaʿ</em> (Niphal of <em>yāḏaʿ</em>, to be known — passive: it was not known); the visible condition of the lean cows after consuming the fat ones was unchanged — the sign of an absolute famine that leaves no trace of former abundance. <em>Qereb</em> (inner part, belly — used for the interior of the body; the cows\' physical appearance contradicted what they had consumed).</p>',
    "22": '<p>The grain dream retold by Pharaoh: the single-stalk-seven-heads image is repeated. The parallel structure of the two dream-pairs (cows/grain; fat-then-lean/full-then-withered) is noted by Pharaoh himself in his retelling — he connects both dreams into a single interpretive puzzle. The accuracy of the retelling confirms that the dream was vivid and memorable.</p>',
    "23": '<p><strong>צְנֻמוֹת דַּקּוֹת שְׁדוּפוֹת קָדִים</strong> (<em>ṣĕnumôt daqqôt šĕḏûpôt qāḏîm</em>) — "withered, thin, scorched by the east wind." Pharaoh adds a third adjective in his retelling: <em>ṣānûm</em> (withered, dried up — from a root related to dryness; appearing only here) alongside <em>daqqôt</em> (thin) and <em>šĕḏûpôt qāḏîm</em> (east-wind scorched). The intensification of the description of the withered grain parallels the intensification of the ugly-cow description (v. 19).</p>',
    "24": '<p><strong>וָאֹמַר אֶל-הַחַרְטֻמִּים וְאֵין מַגִּיד לִי</strong> (<em>wāʾōmar ʾel-haḥarṭummîm wĕʾên maggîḏ lî</em>) — "I told this to the magicians, but none could explain it to me." The <em>ḥarṭummîm</em>\'s failure is confirmed in Pharaoh\'s own words: professional Egyptian dream-interpretation could not decode what God revealed. <em>Maggîḏ</em> (Hiphil participle of <em>nāḡaḏ</em>, to tell, declare, make known — the same root used for Joseph\'s self-disclosure: <em>wayyaggēḏ yôsēp</em> when he reveals himself in 45:1); no one among Egypt\'s professionals could "make known" the interpretation.</p>',
    "25": '<p><strong>חֲלוֹם פַּרְעֹה אֶחָד הוּא</strong> (<em>ḥălôm parʿōh ʾeḥāḏ hûʾ</em>) — "the dream of Pharaoh is one." Joseph\'s opening declaration: the two dreams have a single meaning. <em>ʾEḥāḏ</em> (one) — the unifying declaration; the God of Israel who is <em>ʾeḥāḏ</em> (one, Deut 6:4) speaks in one message even through two dreams. <strong>אֵת אֲשֶׁר הָאֱלֹהִים עֹשֶׂה הִגִּיד לְפַרְעֹה</strong> (what God is doing, he has declared to Pharaoh) — <em>higgîḏ</em> (Hiphil of <em>nāgaḏ</em>, to declare, to make known — the prophetic vocabulary of divine disclosure); the dreams are not random or self-generated but divine disclosure. Note the shift: the <em>ḥarṭummîm</em> could not "make known" the interpretation; God "makes known" what he is about to do.</p>',
    "26": '<p><strong>שֶׁבַע פָּרֹת הַטֹּבֹת שֶׁבַע שָׁנִים הֵנָּה</strong> — "the seven good cows are seven years." Joseph gives the interpretation in the form of equation: dream-symbol = historical reality. The identification of symbolic elements with years is standard ANE dream-interpretation; Joseph\'s identification connects Egypt\'s agricultural patterns (Nile flooding → crop production) to a seven-year divine plan. <em>Hûʾ ḥălôm ʾeḥāḏ hûʾ</em> (it is one dream, it is one) — the emphatic repetition of the unity-declaration; the doubling of <em>ʾeḥāḏ hûʾ</em> in v. 26 reinforces what v. 25 established.</p>',
    "27": '<p><strong>שֶׁבַע שְׁנֵי רָעָב הֵנָּה</strong> (<em>šeḇaʿ šĕnê rāʿāḇ hēnnāh</em>) — "these are seven years of famine." <em>Rāʿāḇ</em> (famine, hunger — the word used for the famines of Abraham\'s era [12:10], Isaac\'s era [26:1], and now the great famine of Joseph\'s time; it will recur in the era of Ruth and Naomi [Ruth 1:1] and the time of Elijah [1 Kgs 18:2]). The parallel identification: seven good cows = seven good years; seven lean cows = seven famine years; seven good heads = seven good years; seven withered heads = seven famine years. The double-dream means the meaning is confirmed twice: Joseph will explain the mechanism in v. 32.</p>',
    "28": '<p>The restatement of Joseph\'s summary: "it is just as I said to Pharaoh: God has shown Pharaoh what he is about to do." <em>Hĕrʾāh</em> (Hiphil of <em>rāʾāh</em>, to cause to see, to show — God caused Pharaoh to see/know his plan). The repetition (v. 25: "God has declared"; v. 28: "God has shown") uses two different disclosure verbs (<em>nāḡaḏ</em> and <em>rāʾāh</em>), both attributing the dreams\' content to divine initiative.</p>',
    "29": '<p><strong>שֶׁבַע שָׁנִים בָּאוֹת שָׂבָע גָּדוֹל</strong> (<em>šeḇaʿ šānîm bāʾôt śāḇāʿ gāḏôl</em>) — "seven years of great abundance are coming." <em>Śāḇāʿ</em> (abundance, satiety — from <em>śāḇaʿ</em>, to be satisfied, to have enough; used for the complete satisfaction of having eaten well; Prov 3:10; Joel 2:26; the word describes not just sufficiency but fullness beyond need). <em>Bāʾôt</em> (Qal active participle, plural: coming — the participle of approach; the abundance is already on its way, already in motion).</p>',
    "30": '<p><strong>וְנִשְׁכַּח כָּל-הַשָּׂבָע</strong> (<em>wĕniškaḥ kol-haśśāḇāʿ</em>) — "all the abundance will be forgotten." <em>Šāḵaḥ</em> (to forget — the verb that the cupbearer used when he "forgot" Joseph [40:23]; now the entire period of Egyptian abundance will be forgotten by the famine that follows; the forgetting-verb is ironically rich in the Joseph narrative). <em>Wĕḵillāh hārāʿāḇ ʾet-hāʾāreṣ</em> (the famine will ravage/destroy the land) — <em>kālāh</em> (Piel: to finish off, consume, destroy — the intensive destruction; the Piel is stronger than the simple completion: it destroys thoroughly).</p>',
    "31": '<p><strong>וְלֹא-יִוָּדַע הַשָּׂבָע בָּאָרֶץ</strong> (<em>wĕlōʾ-yiwwāḏaʿ haśśāḇāʿ bāʾāreṣ</em>) — "the abundance will not be known in the land." The future passive: the abundance will not be knowable; it will leave no evidence. This echoes the dream\'s detail (v. 21): the lean cows that consumed the fat ones "looked just as ugly as before" — the famine erases the abundance visually in the dream and historically in reality.</p>',
    "32": '<p><strong>וְעַל הִשָּׁנוֹת הַחֲלוֹם אֶל-פַּרְעֹה פַּעֲמָיִם כִּי-נָכוֹן הַדָּבָר מֵעִם הָאֱלֹהִים</strong> — "the reason the dream was given twice is that the matter is established from with God." <em>Nāḵôn</em> (Niphal of <em>kûn</em>, to be established, confirmed, prepared — the certainty of fixity; a Niphal participle: "it is established"); <em>mēʿim hāʾĔlōhîm</em> (from with God — <em>ʿim</em> = with, beside; the matter issues from God\'s deliberated will). <strong>וּמְמַהֵר הָאֱלֹהִים לַעֲשֹׂתוֹ</strong> (and God is hastening to do it) — <em>māhar</em> (Piel: to hasten, act urgently — the same urgency as the Passover eating [Exod 12:11: "you shall eat it with urgency"]; the divine plan is not only certain but imminent). The two-dream confirmation (v. 32) is a theological principle: God confirms his word through repetition (cf. Deut 17:6; 19:15 — two witnesses; 2 Cor 13:1).</p>',
    "33": '<p><strong>וְעַתָּה יֵרֶא פַרְעֹה אִישׁ נָבוֹן וְחָכָם</strong> (<em>wĕʿattāh yēreh parʿōh ʾîš nāḇôn wĕḥāḵām</em>) — "now let Pharaoh look for a discerning and wise man." Joseph moves from interpretation to policy recommendation without waiting to be asked — an audacious move for a prisoner. <em>Nāḇôn</em> (discerning, insightful — Niphal participle of <em>bîn</em>, to understand, perceive; the <em>naḇôn</em> is the one who has penetrating perception; cf. Prov 1:5; 10:13; the combination <em>nāḇôn wĕḥāḵām</em> appears in Deut 1:13 for the qualifications of tribal leaders and in 1 Sam 16:18 for David\'s qualities). The qualities Joseph recommends are exactly the ones Pharaoh will identify in Joseph himself (v. 39).</p>',
    "34": '<p><strong>וִיפְקֵד פְּקִדֹת עַל-הָאָרֶץ</strong> (<em>wîpaqēḏ pĕqiḏōt ʿal-hāʾāreṣ</em>) — "let him appoint overseers over the land." The cognate accusative <em>pāqaḏ pĕqiḏōt</em> (appoint appointments/officials) — the <em>pāqaḏ</em> verb is the covenantal-visit word: YHWH "visits" his people in judgment and redemption (21:1; 50:24-25); here used for the administrative appointment of commissioners; the same root as <em>pāqîd</em> (official, overseer; cf. Esth 2:3). <em>ʿAmmēš ʾet-ʾereṣ miṣrāyim</em> (to take a fifth of the harvest) — the twenty-percent grain tax during the seven years of abundance; the taxation plan concentrates the surplus under Pharaoh\'s authority.</p>',
    "35": '<p><strong>וְיִצְבְּרוּ-בָר תַּחַת יַד-פַּרְעֹה</strong> (<em>wĕyiṣbĕrû-ḇār taḥat yaḏ-parʿōh</em>) — "let them collect grain under Pharaoh\'s authority." <em>Ṣāḇar</em> (to heap up, accumulate — used in Exod 8:10 for the heaped frogs; Zech 9:3 for heaped silver; here for the systematic accumulation of grain surpluses). <em>Bār</em> (processed/clean grain — specifically grain that has been cleaned and separated from chaff; the higher-quality designation emphasizes that the stored food will be usable). <em>Taḥat yaḏ-parʿōh</em> (under the hand of Pharaoh) — under royal authority; the centralized storage system under Pharaoh\'s control is the key of the plan.</p>',
    "36": '<p><strong>לְמִחְיָה לָאָרֶץ</strong> (<em>lĕmiḥyāh lāʾāreṣ</em>) — "for the sustaining of life for the land." <em>Miḥyāh</em> (sustenance, means of life — from <em>ḥāyāh</em>, to live; literally "that which gives life"; appears in Judg 6:4 for the grain left to the Israelites by Midian; the word for life-sustaining food). The goal of the storage plan is explicitly stated: <em>wĕlōʾ-tiḵkaret hāʾāreṣ bārāʿāḇ</em> (so that the land may not be cut off by the famine) — <em>kārat</em> (to be cut off — the covenant-curse word; to be "cut off" is the penalty for covenant violation [Exod 12:15, 19; 31:14; Lev 7:20-21]; here it is famine\'s threat to the land).</p>',
    "37": '<p><strong>וַיִּיטַב הַדָּבָר בְּעֵינֵי פַרְעֹה</strong> (<em>wayyîṭaḇ haddāḇār bĕʿênê parʿōh</em>) — "the plan seemed good in Pharaoh\'s eyes." The standard formula of approval: <em>ṭōḇ bĕʿênê</em> (good in the eyes of) = to please, to seem right to; the idiom of subjective acceptance. <em>Ûḇĕʿênê kol-ʿăḇāḏāyw</em> (and in the eyes of all his servants) — unanimous approval; the plan was not just acceptable to Pharaoh but to his entire court. The universal approval legitimizes Joseph\'s appointment: it is not Pharaoh\'s whim but court consensus.</p>',
    "38": '<p><strong>הֲנִמְצָא כָזֶה אִישׁ אֲשֶׁר רוּחַ אֱלֹהִים בּוֹ</strong> (<em>hăniṣmāʾ ḵāzeh ʾîš ʾăšer rûaḥ ʾĔlōhîm bô</em>) — "can we find a man like this, one in whom is the spirit of God?" <em>Rûaḥ ʾĔlōhîm</em> (spirit of God) — on the lips of Pharaoh, this phrase likely means "divine spirit" in the Egyptian sense (the spirit of the gods); in the Hebrew narrative it is presented as the Spirit of Israel\'s God. The same phrase as Gen 1:2 where the Spirit of God hovered over the waters at creation; and as Exod 31:3; 35:31 where Bezalel is filled with the Spirit of God for the tabernacle\'s artistry. Pharaoh inadvertently identifies the source of Joseph\'s gifts: the Spirit that creates and orders is the same Spirit that reveals and interprets.</p>',
    "39": '<p><strong>אַחֲרֵי הוֹדִיעַ אֱלֹהִים אוֹתְךָ אֶת-כָּל-זֹאת</strong> (<em>ʾaḥărê hôḏîaʿ ʾĔlōhîm ʾôtĕḵā ʾet-kol-zōʾt</em>) — "since God has made all this known to you." <em>Hôḏîaʿ</em> (Hiphil of <em>yāḏaʿ</em>, to cause to know, to reveal — the Hiphil causative; God caused Joseph to know; the knowledge did not originate with Joseph). <em>Nāḇôn wĕḥāḵām</em> (discerning and wise) — the exact qualities Joseph had recommended in v. 33 are now applied to Joseph himself by Pharaoh: the recommender is identified as the best candidate. The narrative\'s wit: Joseph did not nominate himself but described himself.</p>',
    "40": '<p><strong>עַל-בֵּיתִי יִשַּׁק כָּל-עַמִּי</strong> (<em>ʿal-bêtî yiššaq kol-ʿammî</em>) — "all my people shall be subject to your orders." <em>Nāšaq</em> (Qal: to kiss; but here in the context of the formula, likely a homophone meaning "to submit, to be ruled by"; some read this as "all my people will be at your beck and call" — the ruler-submission idiom); the idiom is debated but the sense is clear: Joseph has supreme authority over the Egyptian populace. <em>Raq hakkissēʾ ʾeḡdal mimmeka</em> (only the throne will I be greater than you) — the sole exception to Joseph\'s authority is Pharaoh himself; the throne is the only thing Joseph does not receive.</p>',
    "41": '<p><strong>רְאֵה נָתַתִּי אֹתְךָ עַל כָּל-אֶרֶץ מִצְרָיִם</strong> (<em>rĕʾēh nāṯattî ʾōtĕḵā ʿal kol-ʾereṣ miṣrāyim</em>) — "see, I have set you over all the land of Egypt." The perfect tense <em>nāṯattî</em> (I have given/set — a performative perfect: the declaration makes it so; the speech-act is the appointment); Pharaoh\'s word of installation is itself the legal act. <em>Rĕʾēh</em> (see! behold! — the imperative used for drawing attention to a decisive action or proclamation; cf. 41:41; Deut 1:8: "See, I have given you the land").</p>',
    "42": '<p><strong>טַבַּעְתּוֹ מֵעַל יָדוֹ</strong> (<em>ṭabbaʿtô mēʿal yāḏô</em>) — "his signet ring from his hand." <em>Ṭabbaʿat</em> (signet ring — the seal-ring used for authenticating royal documents in wax; the transfer of the signet ring is the transfer of Pharaoh\'s authority for official acts; cf. Esth 3:10; 8:2 where the same ring-transfer signals authority). <strong>בִּגְדֵי-שֵׁשׁ</strong> (<em>bigdê-šēš</em>, garments of fine linen) — <em>šēš</em> (fine linen — an Egyptian word for high-quality bleached linen; the same word used for the tabernacle\'s linen hangings: Exod 26:1, 31, 36; 27:9, 16, 18; and for the priestly garments: Exod 28:5-6, 8, 15, 39). <strong>רְבִד הַזָּהָב</strong> (<em>rĕḇîḏ hazzāhāḇ</em>, the gold chain/necklace) — <em>rĕḇîḏ</em> (necklace, chain — hapax apart from Ezek 16:11; the gold neck-chain is an Egyptian royal honor; the three tokens of appointment: signet ring + fine linen + gold chain = the full Egyptian investiture ceremony).</p>',
    "43": '<p><strong>אַבְרֵךְ</strong> (<em>ʾaḇrēḵ</em>) — the word called out before Joseph\'s chariot; a genuine hapax legomenon of uncertain etymology. Proposed readings: (1) Egyptian <em>ib-r-k</em> or similar = "bow the knee/head in homage"; (2) Hebrew root <em>bāraḵ</em> (to bless/kneel) with the Egyptian definite article or prefix; (3) Akkadian cognate; the LXX transliterates it without translation (<em>abrek</em>), suggesting it was already opaque to early translators. The form and function are clear — a cry of honor and submission as the second-chariot passes — even if the precise linguistic origin is disputed. Joseph rides in Pharaoh\'s second chariot (<em>merkĕḇet hamišneh</em>): the chariot of the second-in-command, the vice-royal chariot.</p>',
    "44": '<p><strong>אֲנִי פַרְעֹה וּבִלְעָדֶיךָ לֹא-יָרִים אִישׁ אֶת-יָדוֹ וְאֶת-רַגְלוֹ</strong> — "I am Pharaoh, but without you no man will lift hand or foot in all Egypt." The formula "I am Pharaoh" (<em>ʾănî parʿōh</em>) echoes the covenant-declaration formula "I am YHWH" (<em>ʾănî YHWH</em>); Pharaoh uses the royal self-identification to validate the decree. <em>Wĕḇilʿāḏeḵā</em> (but without you — the same idiom Joseph used in v. 16: "apart from me, God will answer"; now Pharaoh uses it: "apart from you, no one acts"). The irony is complete: Joseph who said "apart from me" now has Pharaoh say "apart from you."</p>',
    "45": '<p><strong>צָפְנַת פַּעְנֵחַ</strong> (<em>ṣāpĕnat paʿnēaḥ</em>, Zaphenath-Paneah) — an Egyptian throne-name given to Joseph; its exact etymology is disputed: proposed readings include Egyptian <em>ḏd-p-ntr-iw.f-ʿnḫ</em> ("the god speaks and he lives") or <em>ṣnṯ-pꜥ-nḥ</em> ("sustainer of life"); the form is authentically Egyptian despite uncertainty about the precise original. <strong>אָסְנַת בַּת-פּוֹטִי פֶרַע</strong> (Asenath daughter of Potiphera) — <em>ʾĀsĕnat</em> from Egyptian <em>ns-nt</em> ("she who belongs to Neith," the Egyptian goddess of wisdom and war); <em>Pôṭî peraʿ</em> (Potiphera — "gift of Re/the sun god"; cf. the priest Potiphar, possibly the same name-form; both are Egyptian theophoric names containing the sun-god Ra/Re). Joseph\'s wife is the daughter of the priest of <em>ʾÔn</em> (On = Heliopolis, the center of Egyptian sun-worship, the city of the great temple of Re); Joseph is integrated into Egypt\'s highest priestly aristocracy through marriage.</p>',
    "46": '<p><strong>וְיוֹסֵף בֶּן-שְׁלֹשִׁים שָׁנָה בְּעָמְדוֹ לִפְנֵי פַרְעֹה</strong> (<em>wĕyôsēp ben-šĕlōšîm šānāh bĕʿomĕdô lipnê parʿōh</em>) — "Joseph was thirty years old when he stood before Pharaoh." The age datum: thirty is significant in the OT as the age of priestly service (Num 4:3, 23, 30, 35, 39, 43, 47 — Levites begin at thirty), of David\'s kingship (2 Sam 5:4), and of John the Baptist\'s and Jesus\' public ministry (Luke 3:23: "about thirty years old"). Joseph was seventeen when sold (37:2) — thirteen years of servitude and imprisonment before his exaltation. The narrator supplies the chronological marker to anchor the subsequent events.</p>',
    "47": '<p><strong>וַתַּעַשׂ הָאָרֶץ בְּשֶׁבַע שְׁנֵי הַשָּׂבָע לִקְמָצִים</strong> (<em>wattaʿaś hāʾāreṣ bĕšeḇaʿ šĕnê haśśāḇāʿ liqmāṣîm</em>) — "the land produced by handfuls in the seven years of abundance." <em>Qāmāṣ</em> (handful — the standard grain-measure of a handful or fistful; here used to express superabundance: the land produced by the handfuls; the idiom suggests that the grain was so plentiful it could be gathered by the handful and it was still abundant).</p>',
    "48": '<p>Joseph\'s collection system: <em>wayyiṣbōr kol-ʾōkel šeḇaʿ šānîm</em> (he stored all the food of the seven years) — the systematic collection; food from the fields surrounding each city is stored in that city (<em>bĕtôḵāh</em>, within it). The decentralized storage in multiple cities prevents a single point of failure and reduces transportation costs during distribution. The administrative efficiency of Joseph\'s plan reflects the sophisticated Egyptian granary system (attested in archaeological records of Egyptian grain storage).</p>',
    "49": '<p><strong>וַיִּצְבֹּר יוֹסֵף בָּר כְּחוֹל הַיָּם</strong> (<em>wayyiṣbōr yôsēp bār kĕḥôl hayyām</em>) — "Joseph stored up grain like the sand of the sea." The sand-of-the-sea formula — the same comparison used for the promise to Abraham (22:17: "as numerous as the sand on the seashore"); now the covenant-promise of innumerable descendants finds an ironic parallel in the innumerable grain Joseph stores. <em>ʿAḏ kî-ḥāḏal lisepōr kî-ʾên mispar</em> (until he stopped counting because it was beyond number) — the bookkeeping stopped because the quantity exceeded recording capacity; the storage was literally uncountable.</p>',
    "50": '<p><strong>וּלְיוֹסֵף יֻלַּד שְׁנֵי בָנִים</strong> (<em>ûlĕyôsēp yullaḏ šĕnê ḇānîm</em>) — "two sons were born to Joseph." The Niphal passive: were born to him; the children come before the famine. <em>Liphê bôʾ šĕnat hārāʿāḇ</em> (before the year of famine came) — the chronological marker places the birth of Joseph\'s sons in the abundance period; the children are born in Egypt, to an Egyptian wife, in the years of plenty — fully embedded in Egyptian life. The names Joseph gives them will explain his theological interpretation of his exile.</p>',
    "51": '<p><strong>מְנַשֶּׁה כִּי-נַשַּׁנִי אֱלֹהִים אֶת-כָּל-עֲמָלִי</strong> (<em>mĕnaššeh kî-naššanî ʾĔlōhîm ʾet-kol-ʿămālî</em>) — "Manasseh, for God has made me forget all my trouble." The name-etymology is explicit: <em>mĕnaššeh</em> from <em>naššanî</em> (made me forget — Piel of <em>nāšāh</em>, to forget; the Piel causative: God caused the forgetting). <em>ʿĀmāl</em> (trouble, toil — the painful labor; cf. Eccl 2:11 where <em>ʿāmāl</em> is all the toilsome striving under the sun; Job 3:10 where <em>ʿāmāl</em> is life\'s suffering) + <em>bêt ʾāḇî</em> (my father\'s household) — Joseph attributes his forgetting of the pain of his father\'s house to God\'s providential mercy. The statement is psychologically complex: does forgetting his father\'s household mean healing, or is it a sign of Egypt\'s assimilation erasing his origins?</p>',
    "52": '<p><strong>אֶפְרַיִם כִּי-הִפְרַנִי אֱלֹהִים בְּאֶרֶץ עָנְיִי</strong> (<em>ʾeprayim kî-hiprānî ʾĔlōhîm bĕʾereṣ ʿonyî</em>) — "Ephraim, for God has made me fruitful in the land of my affliction." <em>ʾEprayim</em> from <em>hiprānî</em> (Hiphil of <em>pārāh</em>, to be fruitful, to cause fruitfulness; the Hiphil causative: God made fruitful; cf. Gen 1:22, 28: <em>pĕrû ûrĕḇû</em>, "be fruitful and multiply" — the creation blessing now applied to Joseph\'s Egyptian sojourn). <em>ʿOnî</em> (affliction, poverty — the same word used for Israel\'s bondage in Egypt in Exod 3:7 ["I have seen the affliction of my people"]; and for Leah\'s affliction seen by YHWH in Gen 29:32). Joseph names his Egypt experience "the land of my affliction" — Egypt is simultaneously the place of his fruitfulness and his suffering.</p>',
    "53": '<p>The transition verse: "the seven years of abundance that existed in Egypt came to an end." <em>Tāmmannāh</em> (they were completed — Qal of <em>tāmam</em>, to be complete, finished; the years ran their full course exactly as predicted). The transition is stark and brief — one verse for seven years of abundance ending; the brevity mirrors the famine\'s erasure of the abundance.</p>',
    "54": '<p><strong>וַתָּחֵל שֶׁבַע שְׁנֵי הָרָעָב לָבוֹא כַּאֲשֶׁר אָמַר יוֹסֵף</strong> — "the seven years of famine began, just as Joseph said." <em>Kāʾăšer ʾāmar yôsēp</em> (just as Joseph said) — the fulfillment-formula; the narrative credits Joseph\'s interpretation as having been accurate; the proof of prophetic interpretation is fulfillment (cf. Deut 18:22). <em>Rāʿāḇ bĕḵol-hāʾărāṣôt</em> (famine in all the lands) — the scope expands beyond Egypt: the famine is international, not local; this sets up the brothers\' journey from Canaan.</p>',
    "55": '<p><strong>וַתִּרְעַב כָּל-אֶרֶץ מִצְרַיִם</strong> (<em>wattiṛʿaḇ kol-ʾereṣ miṣrāyim</em>) — "all the land of Egypt was hungry." <em>Rāʿēḇ</em> (to be hungry — the verb matching the noun <em>rāʿāḇ</em>, famine/hunger); Egypt itself, despite the stored grain, is hungry. <strong>לְכוּ אֶל-יוֹסֵף אֲשֶׁר-יֹאמַר לָכֶם תַּעֲשׂוּ</strong> (go to Joseph; what he says to you, do it) — Pharaoh\'s directive echoes the Egyptian idiom of total delegation; and it strikingly echoes the words that Mary will say at Cana: "whatever he says to you, do it" (John 2:5; drawing on the same structural pattern of absolute authority). Joseph is the one to whom all Egypt is directed.</p>',
    "56": '<p><strong>וַיִּפְתַּח יוֹסֵף אֶת-כָּל-אֲשֶׁר בָּהֶם</strong> (<em>wayyipttaḥ yôsēp ʾet-kol-ʾăšer bāhem</em>) — "Joseph opened all that was in them." The verb <em>pātaḥ</em> (to open — the opening of the storehouses; the same word used for God "opening" the womb [29:31; 30:22] and "opening" the heavens [Gen 7:11]). Joseph "sells" (<em>wayyišbōr</em>, from <em>šābar</em>, to buy/sell grain — a grain-trade verb; Amos 8:5-6 uses the same root for the dishonest grain-sellers; the root is specifically for grain-commerce).</p>',
    "57": '<p><strong>וְכָל-הָאָרֶץ בָּאוּ מִצְרַיְמָה לִשְׁבֹּר אֶל-יוֹסֵף</strong> (<em>wĕḵol-hāʾāreṣ bāʾû miṣrāymāh lišbōr ʾel-yôsēp</em>) — "all the earth came to Egypt to buy grain from Joseph." <em>Kol-hāʾāreṣ</em> (all the earth/land) — the scope is universal; Joseph has become the grain-provider for the known world. The phrase that will bring his brothers: the famine that was universal means Canaan too is affected; Jacob\'s sons will soon be among those who "came to Egypt to buy grain from Joseph." The chapter ends with Joseph at the center of the world\'s food supply — the dreamer of sheaves bowed to by his brothers has become the actual supplier of grain to all nations.</p>'
  },
  "42": {
    "1": '<p><strong>לָמָּה תִּתְרָאוּ</strong> (<em>lāmmāh titrāʾû</em>) — "why do you just keep looking at each other?" The Hitpael of <em>rāʾāh</em> (to see oneself, to look at one another — the reflexive-reciprocal form; Hitpael implies mutual, repeated looking: they are staring at each other without acting). The idiom expresses paralytic indecision in a crisis — looking around for someone else to take initiative. Jacob\'s blunt rhetorical question breaks the paralysis: the patriarch names the situation and commands action.</p>',
    "2": '<p><strong>רְדוּ-שָׁמָּה וְשִׁבְרוּ-לָנוּ מִשָּׁם</strong> (<em>rĕḏû-šāmmāh wĕšiḇrû-lānû miššām</em>) — "go down there and buy for us from there." <em>Rāḏaḏ</em> (to go down — cf. the later "going down" to Egypt by Jacob [46:3-4]; the geographical descent from Canaan to Egypt is built into the Hebrew verb). <em>Šāḇar</em> (to buy grain — the grain-commerce verb of 41:56-57; Jacob uses the technical term of Joseph\'s operation). <strong>וְנִחְיֶה וְלֹא נָמוּת</strong> (that we may live and not die) — the stark life-or-death alternative; <em>ḥāyāh</em> (to live) versus <em>mût</em> (to die); the existential famine-demand reduced to its essence.</p>',
    "3": '<p><strong>עֲשֶׂרֶת אֲחֵי יוֹסֵף</strong> (<em>ʿăśeret ʾăḥê yôsēp</em>, the ten brothers of Joseph) — the narrator identifies them by their relationship to Joseph, not to Jacob: "Joseph\'s brothers," not "Jacob\'s sons." The perspective is already moving toward Joseph\'s vantage point. The number ten is prominent: Benjamin is withheld; the eleven of the dream-vision will only be complete when Benjamin arrives in Egypt.</p>',
    "4": '<p><strong>פֶּן-יִקְרָאֶנּוּ אָסוֹן</strong> (<em>pen-yiqrāʾennû ʾāsôn</em>) — "lest harm come to him." <em>ʾĀsôn</em> (harm, fatal disaster — a rare word appearing only 5 times in the OT: here, 42:38; 44:29 [twice]; Exod 21:22-23; in each context it refers to a serious physical harm, possibly death; cf. Exod 21:22-23 where <em>ʾāsôn</em> distinguishes minor injury from fatal harm in the pregnant-woman scenario). The word Jacob uses for his fear about Benjamin is the same word he will use when refusing to send Benjamin (42:38; 44:29) — the vocabulary of his protective anxiety forms a refrain.</p>',
    "5": '<p><strong>כִּי-הָיָה הָרָעָב בְּאֶרֶץ כְּנָעַן</strong> — "for the famine was in the land of Canaan also." The <em>gam</em> (also) of v. 5 (implied in "also") connects Canaan to the universal scope of the famine that v. 57 described: "all the earth" came to Egypt; now we see that includes Canaan. The sons of Israel are among the international crowd seeking grain — not distinguished by privilege but by the same hunger that drives all nations to Joseph.</p>',
    "6": '<p><strong>וַיִּשְׁתַּחֲווּ-לוֹ אַפַּיִם אָרְצָה</strong> (<em>wayyištaḥăwû-lô ʾappayim ʾarṣāh</em>) — "they bowed down to him with their faces to the ground." The fulfillment of the first dream: in 37:7, the brothers\' sheaves "bowed down to" Joseph\'s sheaf (<em>wattištaḥăweynāh... lʾălummāṯî</em>). Now the men themselves bow (<em>wayyištaḥăwû-lô</em>) — the same Hishtaphel of <em>šāḥāh</em>. <em>ʾAppayim ʾarṣāh</em> (nostrils to the ground — the prostration posture; literally "with their nostrils to the ground"); the full prostration, not a nodding bow. Twenty-two years after the dream, its first half is fulfilled without anyone recognizing it.</p>',
    "7": '<p><strong>וַיַּכֵּר יוֹסֵף אֶת-אֶחָיו וְהֵם לֹא הִכִּרֻהוּ</strong> (<em>wayyakkēr yôsēp ʾet-ʾeḥāyw wĕhēm lōʾ hikkirûhû</em>) — "Joseph recognized his brothers but they did not recognize him." The same recognition-verb (<em>nākar</em>) that Jacob used when "recognizing" the bloody robe (37:33: <em>wayyakkirāh</em>) and that the brothers used when sending the robe ("please recognize": <em>hakkēr-nāʾ</em>, 37:32). Recognition runs through the Joseph narrative: the robe recognized, the brothers recognized but unrecognized. <strong>וַיִּתְנַכֵּר אֲלֵיהֶם</strong> (<em>wayyitnakkēr ʾălêhem</em>) — "he feigned to be a stranger to them" — Hitpael of <em>nākar</em>: to make oneself unrecognizable, to play the stranger. Joseph actively performs non-recognition; the same root is used both for genuine recognition and for performed concealment.</p>',
    "8": '<p><strong>וְיוֹסֵף הִכִּיר אֶת-אֶחָיו וְהֵם לֹא הִכִּרֻהוּ</strong> — "Joseph recognized his brothers but they did not recognize him." The repetition of the non-recognition formula from v. 7 is not redundant but emphatic: the narrator wants the reader to sit with this fact before the narrative continues. The asymmetry of recognition — Joseph knows everything; the brothers know nothing — will drive every subsequent scene until Joseph\'s disclosure in ch. 45.</p>',
    "9": '<p><strong>וַיִּזְכֹּר יוֹסֵף אֵת הַחֲלֹמוֹת אֲשֶׁר חָלַם לָהֶם</strong> (<em>wayyizkōr yôsēp ʾet haḥălōmôt ʾăšer ḥālam lāhem</em>) — "Joseph remembered the dreams he had dreamed about them." <em>Zākar</em> (to remember — the covenantal memory-verb; God "remembers" his covenant; the cupbearer "forgot" Joseph [šāḵaḥ, 40:23]; now Joseph "remembers" the dreams). The dreams are what he dreams "about them" (<em>lāhem</em>) — the brothers are the content of the dreams; seeing them prostrating triggers the dream-memory. <strong>מְרַגְּלִים אַתֶּם</strong> (<em>mĕragglîm ʾattem</em>, you are spies) — <em>rāgal</em> (to go about as a spy, to slander; Piel participle: professional spies/scouts); the same root used for the twelve scouts of Num 13 whose negative "report" (<em>dibbāh</em>) of the land echoes Joseph\'s "bad report" of his brothers in 37:2.</p>',
    "10": '<p><strong>לֹא אֲדֹנִי</strong> (<em>lōʾ ʾăḏōnî</em>, no, my lord) — the brothers address Joseph with the submission formula <em>ʾăḏōnî</em> (my lord — the title of social superiority); the same title Jacob used in his message to Esau (32:4-5: "my lord Esau... your servant Jacob"). The brothers use the lord-servant language instinctively in the presence of authority; they are speaking to their own brother as "my lord" exactly as the dream predicted their submission. <em>Liḵĕnôt-ʾōḵel</em> (to buy food) — food, not intelligence; the economic desperation motivating the trip is real.</p>',
    "11": '<p><strong>כֻּלָּנוּ בְּנֵי אִישׁ אֶחָד נַחְנוּ</strong> (<em>kullānû bĕnê ʾîš ʾeḥāḏ nāḥnû</em>) — "we are all sons of one man." The brothers appeal to their family unity as proof of good faith: a united family has no motive for espionage; spies are typically strangers without family connections. <em>Kĕnîm ʾănaḥnû</em> (we are honest men) — <em>kēn</em> (honest, upright, true — the word means "right, correct, honest"; cf. Prov 11:19; the same root as the covenant-loyalty word <em>kēn</em> in many contexts). Their claim of honesty (<em>kĕnîm</em>) will be tested by a process that they cannot escape.</p>',
    "12": '<p>Joseph\'s insistence: "No! You have come to see where our land is undefended." <em>ʿErwat hāʾāreṣ</em> (the nakedness/exposed state of the land) — <em>ʿerwāh</em> (nakedness, exposed state — the same word used for sexual exposure in Lev 18-20; here used for military vulnerability: the "nakedness" of a land is its undefended approaches and weak points that a spy would report). Joseph\'s accusation, though false, has the effect of forcing the brothers into a position where they must prove their identity and family integrity.</p>',
    "13": '<p><strong>שְׁנֵים עָשָׂר עֲבָדֶיךָ אַחִים אֲנַחְנוּ</strong> (<em>šĕnêm ʿāśār ʿăḇāḏeḵā ʾaḥîm ʾănaḥnû</em>) — "your servants, twelve brothers, we are." The brothers identify themselves as twelve — including the absent Benjamin and the missing-presumed-dead Joseph. <em>Wĕhāʾeḥāḏ ʾênennû</em> (and one is no more) — "is no more" (<em>ʾênennû</em> = he is not; the formula of absence/non-existence; cf. Rachel "is no more" in 37:30: "the boy is not there"). The brothers use the same idiom that Reuben used when he found the empty cistern — an irony that Joseph alone can appreciate.</p>',
    "14": '<p>Joseph\'s test-declaration: "it is just as I said to you — you are spies." The false accusation is maintained; Joseph is creating a structure that will bring Benjamin to Egypt without revealing his identity or his plan. The narrative does not tell us whether Joseph had a complete plan at this point or improvised; what is clear is that his response is purposeful: the imprisonment, the three-day wait, and the Simeon-hostage are all elements of a test designed to bring about the family\'s full reunion.</p>',
    "15": '<p><strong>חֵי פַרְעֹה</strong> (<em>ḥê parʿōh</em>, as Pharaoh lives) — the Egyptian royal oath formula; cf. v. 16; 44:5. Joseph swears by Pharaoh\'s life, not by God\'s — he is operating within the Egyptian official context. The oath by Pharaoh\'s life is the highest civil oath available in Egypt; it carries the full weight of royal authority and is binding. Contrasted with v. 18 where Joseph shifts to "I fear God" — the two registers (Egyptian oath and divine fear) coexist in Joseph\'s speech.</p>',
    "16": '<p><strong>שִׁלְחוּ מִכֶּם אֶחָד וְיִקַּח אֶת-אֲחִיכֶם</strong> — "send one of you to get your brother." The test conditions: one brother goes to Canaan; the others are imprisoned while the truth of their claim is checked. <em>Wĕʾattem hēʾāsĕrû</em> (and you will be bound/imprisoned) — <em>ʾāsar</em> (to bind, imprison — the same root as the "binding" of Simeon in v. 24; the brothers who are imprisoned will know, from the inside, what Joseph experienced in his years of imprisonment).</p>',
    "17": '<p><strong>וַיֶּאֱסֹף אֹתָם אֶל-מִשְׁמָר שְׁלֹשֶׁת יָמִים</strong> (<em>wayyeʾĕsōp ʾōtām ʾel-mišmār šĕlōšet yāmîm</em>) — "he put them all in custody for three days." <em>Mišmār</em> (custody, watch — a guarded confinement; cf. 40:3, 4, 7 where the same word describes the prison where Joseph himself was kept). The three days (<em>šĕlōšet yāmîm</em>) — a significant interval in the Joseph narrative (cf. 40:13, 19-20 where three days is the predictive timeline; and 22:4 where the three-day journey to Moriah). Three days of imprisonment gives the brothers time to experience what Joseph experienced.</p>',
    "18": '<p><strong>אֶת-הָאֱלֹהִים אֲנִי יָרֵא</strong> (<em>ʾet-hāʾĔlōhîm ʾănî yārēʾ</em>) — "God I fear." The emphatic word order: <em>ʾĔlōhîm</em> is first in the clause (object before subject and verb) — God is syntactically first; <em>ʾănî</em> (I) is second; <em>yārēʾ</em> (fear, Qal participle) is third. The divine fear (<em>yirʾat ʾĔlōhîm</em>) is the foundation of Joseph\'s ethics throughout: in ch. 39 he refused Potiphar\'s wife by appealing to God (39:9: "how could I do this wicked thing and sin against God?"); now he identifies the same fear as the motive for modifying the harsh test-terms. The <em>yirʾat ʾĔlōhîm</em> is the governing moral principle of the Joseph story.</p>',
    "19": '<p><strong>אַחֵיכֶם הָאֶחָד יֵאָסֵר</strong> (<em>ʾaḥêḵem hāʾeḥāḏ yēʾāsēr</em>) — "one of your brothers will be bound." Joseph modifies the plan: instead of one going free while nine are imprisoned, nine will go free while one stays. The modification is presented as an act of <em>ʾĔlōhîm</em>-fearing mercy: keeping nine imprisoned would risk the starvation of their households. <em>Lĕʿammêḵem</em> (for your starving households) — <em>rāʿāḇ</em> (the famine word applied to their families: "your starving households").</p>',
    "20": '<p><strong>וְאֶת-אֲחִיכֶם הַקָּטֹן תָּבִיאוּ אֵלַי</strong> (<em>wĕʾet-ʾăḥîḵem haqqāṭōn tāḇîʾû ʾēlay</em>) — "bring your youngest brother to me." <em>Qāṭōn</em> (small, youngest — cf. the earlier use: David is the "youngest" [<em>haqqāṭōn</em>] brother [1 Sam 17:14]; the youngest is often the one who reverses expectations). Benjamin is the key: bringing Benjamin proves the brothers\' story and sets up the second phase of Joseph\'s test. <em>Wĕyēʾāmĕnû diḇrêḵem wĕlōʾ tāmûtû</em> (your words will be verified and you will not die) — life and death hang on the word-verification; the test has real stakes.</p>',
    "21": '<p><strong>אֲבָל אֲשֵׁמִים אֲנַחְנוּ</strong> (<em>ʾăḇāl ʾăšēmîm ʾănaḥnû</em>) — "surely we are guilty." <em>ʾĂḇāl</em> (truly, surely — an asseverative particle of strong affirmation, often introducing a counter-truth: "but in fact..." [cf. 17:19; 28:16; 37:33 where <em>ʾăḵēn</em> serves a similar function]). <em>ʾĀšēm</em> (guilty — Qal active participle of <em>ʾāšam</em>, to be guilty, to incur guilt; the root of the guilt-offering [<em>ʾāšām</em>] of Leviticus; this is the only occurrence of this vocabulary in Genesis: the brothers use the technical guilt-language to describe their moral condition). <strong>אֲשֶׁר רָאִינוּ צָרַת נַפְשׁוֹ בְּהִתְחַנְּנוֹ אֵלֵינוּ</strong> (we saw his soul\'s distress when he pleaded with us) — the first retrospective confirmation of ch. 37\'s pit scene: the brothers saw Joseph\'s <em>ṣārat nepeš</em> (distress of soul — <em>ṣārāh</em>, distress + <em>nepeš</em>, soul/self; the innermost suffering); and they heard <em>bĕhiṯḥannĕnô</em> (when he pleaded — Hitpael of <em>ḥānan</em>, to show grace, to beg: the intense reflexive-intensive of the grace-petition; Joseph literally begged for mercy). The narrator did not report this in ch. 37; now the brothers\' guilty memory reveals it twenty-two years later.</p>',
    "22": '<p><strong>הֲלוֹא אָמַרְתִּי אֲלֵיכֶם לֵאמֹר אַל-תֶּחֶטְאוּ בַיָּלֶד</strong> (<em>hălōʾ ʾāmartî ʾălêḵem lēʾmōr ʾal-teḥĕṭĕʾû ḇayyāleḏ</em>) — "did I not say to you \'do not sin against the boy\'?" <em>ḥāṭāʾ</em> (to sin — the standard sin-verb; Reuben frames the sale of Joseph as sin against the boy; the guilt-vocabulary intensifies: <em>ʾāšēmîm</em> [v. 21] + <em>teḥĕṭĕʾû</em> [v. 22]). <strong>דָּמוֹ הִנֵּה נִדְרָשׁ</strong> (<em>dāmô hinnēh niḏrāš</em>) — "now his blood is being required." <em>Nāḏaš</em> (Niphal of <em>dāraš</em>, to seek, require — passive: his blood is demanded; the accountability for bloodshed; cf. Gen 9:5: "your blood I will require" [<em>ʾeḏrōš</em>] — the Noahic covenant\'s bloodguilt principle is invoked by Reuben; the same root).</p>',
    "23": '<p><strong>כִּי הַמֵּלִיץ בֵּינֹתָם</strong> (<em>kî hammēlîṣ bênōtām</em>) — "because an interpreter was between them." <em>Mēlîṣ</em> (interpreter/go-between — from a root that can mean to scoff/mock [cf. Prov 3:34; Ps 1:1] but in the Hiphil can mean to interpret/translate; in this passage, "interpreter" is the standard and contextually obvious reading). Joseph uses an interpreter to maintain his Egyptian identity; his brothers speak freely in Hebrew, assuming they are not understood. The dramatic irony: the brothers\' guilt-speech, their genuine repentance-language, is overheard by the very man they wronged — who understood every word.</p>',
    "24": '<p><strong>וַיִּסֹּב מֵעֲלֵיהֶם וַיֵּבְךְּ</strong> (<em>wayyissōḇ mēʿălêhem wayyēḇkĕ</em>) — "he turned away from them and wept." <em>Sāḇaḇ</em> (to turn, go around — he turned away from their sight); <em>bāḵāh</em> (to weep — Joseph\'s first of five weeping scenes in the Joseph narrative: 42:24; 43:30; 45:2; 45:14-15; 46:29). The weeping is private — he turns away first; the public face returns composed. This pattern (private weeping → controlled public return) characterizes Joseph throughout: the emotional reality is genuine and intense; the public management is strategic. <strong>וַיִּקַּח מֵאִתָּם אֶת-שִׁמְעוֹן</strong> (he took Simeon from them and bound him before their eyes) — Simeon, the second-born; Reuben (the firstborn) spoke for rescue in 37:21-22; Judah (the fourth) proposed the sale in 37:26-27; Simeon is neither the rescuer nor the ringleader but is selected as the hostage, possibly as the oldest brother available (Reuben must return to Jacob) or as the one associated with violent revenge (34:25).</p>',
    "25": '<p><strong>לְמַלֵּא אֶת-כְּלֵיהֶם בָּר וּלְהָשִׁיב כַּסְפֵּיהֶם</strong> (<em>lĕmallēʾ ʾet-kĕlêhem bār ûlĕhāšîḇ kaspêhem</em>) — "to fill their vessels with grain and to return their silver." The silver return is Joseph\'s covert act of providence — or test; the brothers do not know it is happening. <em>Kāsep</em> (silver — the purchase-price of grain; but also the silver for which Joseph was sold: twenty shekels of silver [37:28]; the silver motif returns). <em>Wĕlāṯet lāhem ṣēḏāh laddāreḵ</em> (and to give them provisions for the journey) — additional provisions beyond the grain; Joseph is feeding them even as he tests them.</p>',
    "26": '<p>They load the grain on their donkeys and depart. The departure is businesslike; the emotional scene of Simeon\'s binding (v. 24) is followed immediately by the practical loading and leaving. The narrative speed — loading, departing — mirrors the brothers\' desire to leave an uncomfortable situation. The silver in the sack is unknown to them at this point.</p>',
    "27": '<p><strong>וַיַּרְא אֶת-כַּסְפּוֹ וְהִנֵּה-הוּא בְּפִי אַמְתַּחְתּוֹ</strong> (<em>wayyarʾ ʾet-kaspô wĕhinnēh-hûʾ bĕpî ʾamtaḥtô</em>) — "he saw his silver — and there it was in the mouth of his sack." The <em>wĕhinnēh</em> (and behold!) of sudden, startling discovery; the silver appears unexpectedly at the stopping-place for the night. <em>Pî ʾamtaḥtô</em> (the mouth of his sack — <em>peh</em> = mouth; <em>ʾamtaḥat</em> = sack, bag [appearing only in the Joseph narrative]; the mouth/opening of the bag). The silver in the mouth of the sack is a narrative set-piece that creates maximum anxiety: what should be at the bottom (grain) is at the top (silver).</p>',
    "28": '<p><strong>מַה-זֹּאת עָשָׂה אֱלֹהִים לָנוּ</strong> (<em>mah-zōʾt ʿāśāh ʾĔlōhîm lānû</em>) — "what is this that God has done to us?" The brothers immediately interpret the silver as divine action. Their guilt-ridden consciousness reads every unexplained event as judgment: they cannot conceive of an innocent explanation. The question echoes the brothers\' earlier question-of-judgment (they said to each other in v. 21 "we are guilty"); now they interpret the silver as God\'s intervention in their case. The irony: it is God\'s action through Joseph, but not judgment — it is providential care that Joseph provides, even while testing them. <em>Wayyēṣēʾ libbām</em> (their hearts went out/sank — literally "went out"; <em>lēḇ</em> [heart] going out = an idiom for sudden terror; cf. Josh 2:11 where the Canaanites\' "heart went out" when they heard of Israel\'s crossing the Red Sea).</p>',
    "29": '<p>The brothers return to Jacob in Canaan and give a full account of "all that had happened to them." The narrative phrase <em>ʾēt kol-haqqōrōt ʾōtām</em> (all that had befallen them — <em>qārāh</em>, to happen/befall; the events of their Egypt journey are summarized before the detailed retelling of vv. 30-34). The two-level narration (summary + detail) is the pattern of the servant\'s retelling in ch. 24 — embedded retelling that allows the reader to hear the events interpreted through the brothers\' own frame.</p>',
    "30": '<p><strong>דִּבֶּר אִתָּנוּ קָשׁוֹת</strong> (<em>dĭbber ʾittānû qāšôt</em>) — "he spoke harshly/hard things with us." The brothers\' retelling characterizes Joseph\'s speech as <em>qāšôt</em> (hard, harsh words — the same adjective as in v. 7; the brothers accurately report the harshness of Joseph\'s treatment). <em>Hāʾîš ʾăḏōnê hāʾāreṣ</em> (the man who is lord of the land) — they describe Joseph by his title and function, not his identity; to them he is "the lord of the land" — the Egyptian official; they have no idea he is Joseph.</p>',
    "31": '<p>The brothers\' self-defense in their report mirrors their defense to Joseph (vv. 10-11): "we said we are honest men, not spies." <em>Kĕnîm ʾănaḥnû</em> (we are honest men) — the identical formula; their defense was consistent; they are reporting accurately what they said. The retelling confirms their integrity in the encounter even while the narrative reader knows the deep irony: the accused spies are the actual wrongdoers against Joseph, though not in the way Joseph charged them.</p>',
    "32": '<p><strong>אֶחָד אֵינֶנּוּ</strong> (<em>ʾeḥāḏ ʾênennû</em>, one is no more) — the brothers report their own words to Joseph about the missing brother; "one is no more" — the same formula of 37:30. They tell their father that they reported Joseph as dead to the Egyptian lord. The double layer of the original lie (to Jacob) now becomes a public fact, retold in Jacob\'s presence, without knowing Joseph is alive. The concealment of the sale has become part of their family narrative: the missing brother is simply "no more."</p>',
    "33": '<p>The brothers retell Joseph\'s test-conditions: leave one brother as pledge; take grain to your starving households; bring the youngest brother. The retelling to Jacob recapitulates the test for the reader and prepares the conflict of vv. 36-38: Jacob must decide whether to release Benjamin.</p>',
    "34": '<p><strong>אֶת-אֲחִיכֶם הַקָּטֹן</strong> (your youngest brother) — the demand for Benjamin is the hinge of the entire narrative: without Benjamin, the family cannot return to Egypt; without return to Egypt, they cannot eat; without eating, they will die; but sending Benjamin risks the life that Jacob has protected since Rachel\'s death. The test-structure forces Jacob to choose between Benjamin and the family\'s survival.</p>',
    "35": '<p><strong>הִנֵּה אִישׁ צְרוֹר-כַּסְפּוֹ בְּשַׂקּוֹ</strong> (<em>hinnēh ʾîš ṣĕrôr-kaspô bĕśakkô</em>) — "there in each man\'s sack was his pouch of silver!" <em>Ṣĕrôr</em> (bundle, tied-up pouch — a small bundle of money; cf. Song 1:13 where the myrrh is a <em>ṣĕrôr</em>; Prov 7:20 where money is carried in a <em>ṣĕrôr</em>). <em>Wayyirʾû ʾet-ṣĕrōrôt kaspêhem hēmmāh wĕʾăḇîhem wayyîrāʾû</em> (when they and their father saw the money pouches, they were afraid) — the fear is shared between brothers and father; the silver is inexplicable and ominous; Jacob is seeing what the one brother saw at the lodging (v. 27-28), now multiplied tenfold.</p>',
    "36": '<p><strong>אֹתִי שִׁכַּלְתֶּם</strong> (<em>ʾōtî šikkaltĕm</em>) — "you have bereaved me." <em>Šāḵal</em> (Piel: to bereave — the verb used for the loss of children; cf. Lam 1:20; Jer 15:7; here the Piel is intense and accusatory: "you have made me childless"). Jacob\'s accusation is not entirely accurate or fair — the brothers did not cause Joseph\'s disappearance knowingly in Jacob\'s presence, though they did sell him. <strong>כֻּלָּנָה הָיוּ עָלָי</strong> (<em>kullānāh hāyû ʿālay</em>) — "everything is against me!" — <em>kullānāh</em> (all these things — the feminine plural of <em>kōl</em>); the suffix <em>-nāh</em> is an intensive/archaic form. Jacob\'s declaration of total loss is the low point of his perspective: subjectively everything is gone. The narrative irony: everything is in fact working toward reunion.</p>',
    "37": '<p><strong>אֶת-שְׁנֵי בָנַי תָּמִית</strong> (<em>ʾet-šĕnê ḇānay tāmît</em>) — "you may put both of my sons to death." Reuben\'s desperate surety-offer: his two sons as pledge for Benjamin\'s safety. <em>Tāmît</em> (Hiphil of <em>mût</em>, to put to death — the causative; Reuben gives Jacob the right to execute his own grandchildren if he fails). The offer is excessive and reveals Reuben\'s desperation; it is also strategically ineffective — killing Reuben\'s sons would add to Jacob\'s bereavement, not compensate it. Jacob does not even engage with the specific terms of Reuben\'s offer.</p>',
    "38": '<p><strong>לֹא-יֵרֵד בְּנִי עִמָּכֶם</strong> (<em>lōʾ-yēreḏ bĕnî ʿimmāḵem</em>) — "my son will not go down with you." The flat refusal; Jacob uses the singular <em>bĕnî</em> (my son) — in his grief, only Benjamin is "my son"; the others are being addressed as "you." <strong>כִּי-אָחִיו מֵת וְהוּא לְבַדּוֹ נִשְׁאָר</strong> (for his brother is dead and he alone remains) — the statement "his brother is dead" is Jacob\'s belief about Joseph; it is also the brothers\' lie maintained for twenty-two years. <strong>תּוֹרִידוּ אֶת-שֵׂיבָתִי בְּיָגוֹן שְׁאֹלָה</strong> (you will bring my gray head down to Sheol in sorrow) — the same sentence as 37:35 (<em>ʾēreḏ ʾel-bĕnî ʾāḇēl šĕʾōlāh</em>); the formula of grief-unto-death is Jacob\'s refrain across the Joseph story; <em>śêḇāh</em> (gray hair — the white hair of old age; the vulnerable aged parent). The chapter ends in an impasse: Egypt requires Benjamin; Jacob refuses to send him; Simeon remains in prison; the family will starve unless the impasse breaks.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-original', 'genesis', existing)
    print('Genesis 41-42 mkt-original written.')

